import{_ as a,c as n,o as e,ag as p}from"./chunks/framework.D4Vqf8I7.js";const h=JSON.parse('{"title":"Сага о драйверах — ALT Linux Wiki","description":null,"frontmatter":{"title":"Сага о драйверах — ALT Linux Wiki","source":"https://www.altlinux.org/%D0%A1%D0%B0%D0%B3%D0%B0_%D0%BE_%D0%B4%D1%80%D0%B0%D0%B9%D0%B2%D0%B5%D1%80%D0%B0%D1%85","author":null,"published":null,"created":"2025-09-15T00:00:00.000Z","description":null,"tags":["clippings"]},"headers":[],"relativePath":"docs/disciplines/pm2/mdk22/driver_saga.md","filePath":"docs/disciplines/pm2/mdk22/driver_saga.md","lastUpdated":1775218819000}'),i={name:"docs/disciplines/pm2/mdk22/driver_saga.md"};function l(t,s,o,r,c,d){return e(),n("div",null,s[0]||(s[0]=[p(`<p>Статья пишется на основе знаменитой статьи <a href="https://docs.altlinux.org/ru-RU/archive/7.0.5/html-single/simply-linux/index.html#idm45151940002288" target="_blank" rel="noreferrer">&quot;Сага о драйверах&quot;</a></p><p>Замечания и предложения по статье можно посылать в телеграмм канал <a href="https://t.me/Saga_o_Driverah" target="_blank" rel="noreferrer">Saga_o_Driverah</a></p><h2 id="про-установку-драиверов" tabindex="-1">Про установку драйверов <a class="header-anchor" href="#про-установку-драиверов" aria-label="Permalink to &quot;Про установку драйверов&quot;">​</a></h2><p>Перед началом экспериментов с подбором драйвера, если он есть в репозитории, но не входит в основной пакет с ядром, следует ознакомиться со статьёй &quot; <a href="https://www.altlinux.org/%D0%9E%D0%B1%D0%BD%D0%BE%D0%B2%D0%BB%D0%B5%D0%BD%D0%B8%D0%B5_%D1%8F%D0%B4%D1%80%D0%B0#%D0%94%D0%BE%D1%83%D1%81%D1%82%D0%B0%D0%BD%D0%BE%D0%B2%D0%BA%D0%B0_%D0%BC%D0%BE%D0%B4%D1%83%D0%BB%D0%B5%D0%B9_%D1%8F%D0%B4%D1%80%D0%B0" title="Обновление ядра" target="_blank" rel="noreferrer">Обновление_ядра#Доустановка_модулей_ядра</a> &quot;. Данная статья не касается драйверов для принтеров и сканерах, о них читайте в <a href="https://www.altlinux.org/Drivers" title="Drivers" target="_blank" rel="noreferrer">Инструкции по поиску и применению драйверов для принтеров, сканеров и МФУ</a> и смотрите поддержку своего принтера на <a href="https://openprinting.github.io/printers/" target="_blank" rel="noreferrer">OpenPrinting</a></p><h2 id="у-вас-не-работает-железо-что-делать" tabindex="-1">У вас не работает &quot;железо&quot;, что делать <a class="header-anchor" href="#у-вас-не-работает-железо-что-делать" aria-label="Permalink to &quot;У вас не работает &quot;железо&quot;, что делать&quot;">​</a></h2><p>Часто на форуме можно встретить вопрос такого типа:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Я поставил ваш дистрибутив на свой ноутбук, и у меня не работает карточка WiFi&quot;.</span></span></code></pre></div><p>Давайте на примере этого вопроса узнаем кое-что об оборудовании компьютера (дальше для краткости я его буду просто называть &quot;железо&quot;) и о программах,которые с ним работают (для краткости - драйвера).</p><p>&quot;Железо&quot; может быть внутри компьютера, или внешним. Оно может подсоединяться к &quot;сердцу&quot; компьютера, его процессору по различным шинам (линиям связи). Для обеспечения этой связи обычно используется &quot;материнская плата&quot; (видел я и компьютеры, в которых она называлась просто &quot;задняя стенка&quot;😉 ).</p><p>Существует достаточно много различных типов таких шин — USB, PCI, PS/2, SATA, RS-232 (к ней подключены порты COM и LPT) [^1] и т.п.</p><p>Если говорить про карточку Wi-Fi в ноутбуке, то она может находиться или на шине USB, или на шине PCI (я говорю о них как о типе шин, так как, например, USB бывают разными — как, впрочем, и PCI ).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Для обнаружения таких устройств существуют две команды: lspci и lsusb.</span></span></code></pre></div><h3 id="_2" tabindex="-1">2 <a class="header-anchor" href="#_2" aria-label="Permalink to &quot;2&quot;">​</a></h3><p>Вот я сейчас сижу за ноутбуком и даю команду:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ lsusb</span></span>
<span class="line"><span>Bus 002 Device 001: ID 1d6b:0003 Linux Foundation 3.0 root hub</span></span>
<span class="line"><span>Bus 001 Device 001: ID 1d6b:0002 Linux Foundation 2.0 root hub</span></span>
<span class="line"><span>Bus 006 Device 002: ID 0bda:57b4 Realtek Semiconductor Corp. USB Camera</span></span>
<span class="line"><span>Bus 006 Device 001: ID 1d6b:0002 Linux Foundation 2.0 root hub</span></span>
<span class="line"><span>Bus 008 Device 002: ID 13d3:3501 IMC Networks </span></span>
<span class="line"><span>Bus 008 Device 001: ID 1d6b:0001 Linux Foundation 1.1 root hub</span></span>
<span class="line"><span>Bus 005 Device 001: ID 1d6b:0002 Linux Foundation 2.0 root hub</span></span>
<span class="line"><span>Bus 007 Device 004: ID 1ea7:0064 SHARKOON Technologies GmbH 2.4GHz Wireless rechargeable vertical mouse [More&amp;Better]</span></span>
<span class="line"><span>Bus 007 Device 001: ID 1d6b:0001 Linux Foundation 1.1 root hub</span></span>
<span class="line"><span>Bus 004 Device 001: ID 1d6b:0003 Linux Foundation 3.0 root hub</span></span>
<span class="line"><span>Bus 003 Device 001: ID 1d6b:0002 Linux Foundation 2.0 root hub</span></span></code></pre></div><p>Здесь $ - это не часть команды, а приглашение bash и в контексте статьи означает, что команду можно давать от обычного пользователя</p><p>Разберём одну строчку:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bus 007 Device 004: ID 1ea7:0064 SHARKOON Technologies GmbH 2.4GHz Wireless rechargeable vertical mouse [More&amp;Better]</span></span></code></pre></div><ul><li>Bus 007 - устройство висит на седьмой шине USB</li><li>Device 004:- оно на этой шине четвертое</li><li>ID 1ea7:0064 - это его идентификатор, определяющая какая фирма произвела устройство (Id Vendor) и идентификатор самого устройства (Id Device)</li><li>SHARKOON Technologies GmbH 2.4GHz Wireless rechargeable vertical mouse [More&amp;Better] - имя устройства. За его идентификацию отвечает пакет usbids <a href="http://packages.altlinux.org/en/Sisyphus/srpms/usbids" target="_blank" rel="noreferrer">[1]</a></li></ul><p>.</p><p>Допустим нам надо посмотреть какой драйвер (в данном случае модуль ядра) &quot;обслуживает&quot; устройство мыши.</p><p>Для этого даём команду:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># lsusb  -tv</span></span>
<span class="line"><span>/:  Bus 08.Port 1: Dev 1, Class=root_hub, Driver=ohci-pci/5p, 12M</span></span>
<span class="line"><span>    ID 1d6b:0001 Linux Foundation 1.1 root hub</span></span>
<span class="line"><span>    |__ Port 5: Dev 2, If 0, Class=Wireless, Driver=btusb, 12M</span></span>
<span class="line"><span>        ID 13d3:3501 IMC Networks </span></span>
<span class="line"><span>    |__ Port 5: Dev 2, If 1, Class=Wireless, Driver=btusb, 12M</span></span>
<span class="line"><span>        ID 13d3:3501 IMC Networks </span></span>
<span class="line"><span>/:  Bus 07.Port 1: Dev 1, Class=root_hub, Driver=ohci-pci/5p, 12M</span></span>
<span class="line"><span>    ID 1d6b:0001 Linux Foundation 1.1 root hub</span></span>
<span class="line"><span>    |__ Port 1: Dev 4, If 0, Class=Human Interface Device, Driver=usbhid, 12M</span></span>
<span class="line"><span>        ID 1ea7:0064 SHARKOON Technologies GmbH 2.4GHz Wireless rechargeable vertical mouse [More&amp;Better]</span></span>
<span class="line"><span>....</span></span>
<span class="line"><span>    ID 1d6b:0003 Linux Foundation 3.0 root hub</span></span>
<span class="line"><span>/:  Bus 01.Port 1: Dev 1, Class=root_hub, Driver=vhci_hcd/8p, 480M</span></span>
<span class="line"><span>    ID 1d6b:0002 Linux Foundation 2.0 root hub</span></span></code></pre></div><p>Здесь # - это не часть команды, а приглашение bash пользователя root и в контексте статьи означает, что команду нужно давать от пользователя root.</p><p>lsusb -t наглядно показывает какое USB устройство подсоединено к конкретному порту USB, Но нам в данном случае важно, что команда показывает какой драйвер использует то, или иное устройство [^3]. В данном случае, мы видим, например, что &quot;IMC Networks&quot; использует модуль ядра (драйвер) btusb. И мы видим что это составное устройство. Зная устройство своего ноутбука, могу сразу сказать, что это комбинированная внутренняя карточка, одновременно работающая и с Wi-Fi и c bluetooth (сам в своё время покупал, заменив старую карточку).</p><h3 id="_4" tabindex="-1">4 <a class="header-anchor" href="#_4" aria-label="Permalink to &quot;4&quot;">​</a></h3><p>Ну и для примера приведу как работать с командой lspci. На другом компьютере даю команду lspci:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>00:00.0 Host bridge: Advanced Micro Devices, Inc. [AMD] Family 15h (Models 10h-1fh) Processor Root Complex</span></span>
<span class="line"><span>00:00.2 IOMMU: Advanced Micro Devices, Inc. [AMD] Family 15h (Models 10h-1fh) I/O Memory Management Unit</span></span>
<span class="line"><span>00:04.0 PCI bridge: Advanced Micro Devices, Inc. [AMD] Family 15h (Models 10h-1fh) Processor Root Port</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>00:18.4 Host bridge: Advanced Micro Devices, Inc. [AMD] Family 15h (Models 10h-1fh) Processor Function 4</span></span>
<span class="line"><span>00:18.5 Host bridge: Advanced Micro Devices, Inc. [AMD] Family 15h (Models 10h-1fh) Processor Function 5</span></span>
<span class="line"><span>01:00.0 VGA compatible controller: NVIDIA Corporation GF119 [GeForce GT 610] (rev a1)</span></span>
<span class="line"><span>01:00.1 Audio device: NVIDIA Corporation GF119 HDMI Audio Controller (rev a1)</span></span>
<span class="line"><span>03:00.0 Network controller: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter (rev 01)</span></span>
<span class="line"><span>04:00.0 Ethernet controller: Qualcomm Atheros AR8161 Gigabit Ethernet (rev 10)</span></span>
<span class="line"><span>05:00.0 USB controller: Renesas Technology Corp. uPD720201 USB 3.0 Host Controller (rev 03)</span></span></code></pre></div><p>Нас интересует это устройство:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>03:00.0 Network controller: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter (rev 01)</span></span></code></pre></div><ul><li>03:00.0 - это &quot;порт&quot; подключения устройства</li><li>Network controller: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter (rev 01) - его название. За определение названия отвечает пакет pciids <a href="http://packages.altlinux.org/en/Sisyphus/srpms/pciids" target="_blank" rel="noreferrer">[2]</a></li></ul><p>Для поиска драйверов важны идентификаторы вендора (Id Vendor) и устройства (Id Device), именно по ним ищет &quot;операционка&quot; какой драйвер (модуль ядра) нужно загрузить. И по ним легче искать в интернете какой драйвер нужно использовать. Для примера, посмотрим эти идентификаторы у карточки &quot;Network controller: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter (rev 01)&quot;. Мы видим из предыдущей команды, что она подключена к порту 03:00.0. Даём следующую команду:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ lspci -n -s 03:00.0</span></span>
<span class="line"><span>03:00.0 0280: 10ec:8812 (rev 01)</span></span></code></pre></div><p>Что мы видим:</p><ul><li>03:00.0 - это &quot;порт&quot;подключения</li><li>0280: идентификатор контроллера</li><li>10ec:8812 - идентификатор вендора и идентификатор устройства</li></ul><p>Иногда удобнее увидеть и имя устройства, тогда можно дать такую команду:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ lspci -nn -s 03:00.0</span></span>
<span class="line"><span>03:00.0 Network controller [0280]: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter [10ec:8812] (rev 01)</span></span></code></pre></div><p>Для того, чтобы посмотреть какой модуль ядра (драйвер) &quot;обслуживает&quot; сейчас данное устройство надо дать команду:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># lspci -k -s 03:00.0 </span></span>
<span class="line"><span>03:00.0 Network controller: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter (rev 01)</span></span>
<span class="line"><span>        Subsystem: Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter</span></span>
<span class="line"><span>        Kernel driver in use: rtl8821ae</span></span></code></pre></div><p>Как мы видим используется драйвер rtl8821ae</p><p>Хуже бывает, если система не говорит о загруженном драйвере, т.е. отсутствует строчка</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kernel driver in use: rtl8821ae</span></span></code></pre></div><p>В этом случае нам надо искать какой драйвер надо использовать.</p><h2 id="немного-теории" tabindex="-1">Немного теории <a class="header-anchor" href="#немного-теории" aria-label="Permalink to &quot;Немного теории&quot;">​</a></h2><p>Под драйверами [^5] часто понимают все программы, обеспечивающие работу устройств.</p><p>В Линукс можно выделить несколько видов программ, работающих с устройствами.</p><p>Наибольшая часть из таких программ в Линукс входят в ядро. Это почти все драйвера, работающие с внутренними устройствами компьютера и многие устройства использующие шину USB. Большинство из таких драйверов входят в основную ветку разработки ядра и входят в пакет kernel-image. Кроме того, помимо модулей ядра, входящих в основную ветку ядра, существуют модули ядра по какой-либо причине в него не входящие. Обычно это или модули ядра с закрытыми частями от разработчиков &quot;железа&quot;, или новые, ещё не отлаженные до конца, модули.</p><p>Поскольку Linux достаточно динамичная &quot;среда&quot; программирования [^6], то иногда появляется ситуация, что какое-то оборудование могут поддерживать несколько модулей ядра.</p><p>При наличии нескольких конкурирующих модулей для работы с конкретным устройством, возникает задача указать, какой модуль применять. Для этого применяются опции блокировки конкретного модуля. Для этого в каталоге /etc/modprobe.d для этого создаётся файл, обычно с именем blacklist_суффикс.conf [^7] и с опцией blacklist имя_модуля.</p><p>Например, в пакет kernel-modules-e1000e-std-def входит файл blacklist-e1000e.conf с содержимым:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>blacklist e1000e</span></span></code></pre></div><p>Модули ядра расположены в каталоге /lib/modules/ <strong>имя_релиза_ядра</strong>. [^8].</p><p>Помимо модулей ядра с оборудованием работают и модули других программ, которые в обыденной жизни тоже называют драйверами.</p><p>Так со сканерами работают модули программы sane, расположенные в каталоге (для архитектуры <strong>x86_64</strong>) /usr/lib64/sane (входят в пакет libsane). Поддерживаемые сканеры проектом Sane можно посмотреть в <a href="http://www.sane-project.org/sane-supported-devices.html" target="_blank" rel="noreferrer">[3]</a></p><p>А с принтерами работают модули cups, который имеет свои модули поддержки принтеров. Про поддержку принтеров проектом Cups можно посмотреть <a href="https://openprinting.org/printers" target="_blank" rel="noreferrer">[4]</a></p><p>Также существуют отдельные модули, обеспечивающие работу графического режима работы ОС - модули работающие с xorg и c wayland.</p><h2 id="где-искать-драивер" tabindex="-1">Где искать драйвер <a class="header-anchor" href="#где-искать-драивер" aria-label="Permalink to &quot;Где искать драйвер&quot;">​</a></h2><ul><li>во-первых, стоит поставить пакет типа kernel-doc-6.12 / kernel-doc-std-def, но там обычно есть описания только модулей ядра, которые уже входят в ядро.</li><li>во-вторых, на сайте <a href="https://linux-hardware.org/?view=search" target="_blank" rel="noreferrer">linux-hardware.org</a> [^9] есть возможность поискать по идентификаторам вендора и устройства какой драйвер нужен для вашего устройства.</li></ul><p>Например:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ищем карточку Realtek Semiconductor Co., Ltd. RTL8812AE 802.11ac PCIe Wireless Network Adapter по её идентификаторам вендора и устройства, и потом по ссылке находим какой драйвер ядра её поддерживает.</span></span></code></pre></div><ul><li>в-третьих, искать в интернете по идентификаторам, лучше по идентификаторам (Id Vendor и Id Device), в том виде как выдают их команды lsusb и lspci.</li></ul><p>Искать по коммерческому названию устройств не эффективно, так как в поиске получите или описание драйверов для Windows или рекламу купить это устройство.</p><h2 id="немного-о-драиверах-и-прошивках" tabindex="-1">Немного о драйверах и прошивках <a class="header-anchor" href="#немного-о-драиверах-и-прошивках" aria-label="Permalink to &quot;Немного о драйверах и прошивках&quot;">​</a></h2><p>В силу того, между разработчиками оборудования существует конкуренция, его разработчики не заинтересованы подробно делиться подобным кодом их работы. Особенно новыми разработками. Поэтому довольно часто создаются закрытые прошивки, которые загружаются драйвером в ОЗУ компьютера или во внутреннюю память самого устройства. Ещё одна из причин использовать прошивки - их применение уменьшает стоимость аппаратной части устройства.</p><p>Этим &quot;грешат&quot; как некоторые внутренние устройства, например Ethernet и Wi-Fi карты, так и некоторые принтеры и сканеры. Бывают ситуации, что драйвер есть, а прошивки ему не хватает. [^10]</p><p>Например модуль ядра для Wi-Fi Broadcom, входящий на момент написания статьи в основное дерево, требует отдельной прошивки, но условия её распространения не позволяют нет только включать прошивку в дистрибутив, но даже класть в репозиторий (см <a href="https://www.altlinux.org/Wi-fi_Broadcom" title="Wi-fi Broadcom" target="_blank" rel="noreferrer">Wi-fi_Broadcom</a>). Недавно появился модуль bcmwl, устраняющий эту проблему, но он ещё не вошёл в основное дерево ядра и пока распространяется отдельно.</p><p>Ещё одним из вариантом применения прошивок является ситуация, когда создаётся модуль ядра, который умеет работать с импортируемой частью драйвера от другой ОС. Ярким примером такого модуля является история модуля ядра <a href="https://ru.wikipedia.org/wiki/NDISwrapper" target="_blank" rel="noreferrer">ndiswrapper</a>.[^11]</p><h2 id="схема-работы-ядра-с-оборудованием" tabindex="-1">Схема работы ядра с оборудованием <a class="header-anchor" href="#схема-работы-ядра-с-оборудованием" aria-label="Permalink to &quot;Схема работы ядра с оборудованием&quot;">​</a></h2><p>Упрощённо работу ядра с оборудованием можно представить так:</p><ul><li>после загрузки ядра, ядро обнаруживает устройства, которые или находятся внутри компьютера, или присоединены к его внутренним или внешним шинам и распознаёт их по их идентификаторам.</li><li>если модуль ядра не загружен к текущему моменту в ОЗУ (некоторые модули ядра могут входить в основную часть ядра и загружаться как единое целое с ним), то условно &quot;диспетчер&quot; (далее без кавычек) модулей ядра ищет по информации находящейся в модулях ядра, необходимый модуль.</li><li>после нахождения модуля ядра, диспетчер проверяет, есть ли этот модуль в &quot;черном списке&quot; (blacklist) на загрузку, и если нет, то загружает этот модуль ядра</li><li>в момент загрузки модуля диспетчер модулей ядра ищет в /etc/modprobe.d/ информацию о том, с какими параметрами загружать модуль.</li><li>в этот момент, при необходимости, загружается прошивка, нужная для работы модуля.</li><li>в виртуальной файловой системе /sys создаётся информация об устройстве и загруженном модуле ядра для того, чтобы внешние программы могли получить информацию об устройстве и модуле</li><li>запускается udev, который считывает свои правила (/lib/udev/rules.d/*.rules) и в соответствии с ними, создаёт (при необходимости) в файловой системе &quot;устройства&quot; /dev (иногда их называют &quot;нодами устройств&quot;), которые являются одним из каналов общения между программами и устройствами. Ude v может использовать программные средства, которые обеспечивают дальнейшую работу с устройством. Например, usbmodeswitch меняет &quot;заводские&quot; идентификаторы вендора и устройства модема на идентификаторы, аналогичных модемов, поддерживаемых ядром.</li></ul><p>В принципе, в большинстве случаев этого достаточно для начала работы с устройствами.</p><p>Раньше ноды устройств создавались статически. Некоторые ноды и сейчас создаются статически (и их может создать грамотный администратор) и лежат в каталоге /dev уже в момент загрузки устройств. Но теория и практика применения Линукс развивалась и теперь большинство необходимых нод создаются и удаляются динамически.</p><h2 id="про-команды-работы-с-модулями-ядра" tabindex="-1">Про команды работы с модулями ядра <a class="header-anchor" href="#про-команды-работы-с-модулями-ядра" aria-label="Permalink to &quot;Про команды работы с модулями ядра&quot;">​</a></h2><h3 id="команда-lsmod" tabindex="-1">Команда lsmod <a class="header-anchor" href="#команда-lsmod" aria-label="Permalink to &quot;Команда lsmod&quot;">​</a></h3><ul><li>Для того, чтобы понять почему не работает какое-либо устройство, стоит посмотреть какие модули ядра загрузились в ОЗУ. Это можно сделать с помощью команды lsmod.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># lsmod</span></span>
<span class="line"><span>Module                  Size  Used by</span></span>
<span class="line"><span>btrfs                1810432  0</span></span>
<span class="line"><span>blake2b_generic        20480  0</span></span>
<span class="line"><span>xor                    24576  1 btrfs</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ehci_pci               16384  0</span></span>
<span class="line"><span>serio_raw              16384  0</span></span>
<span class="line"><span>ehci_hcd               65536  1 ehci_pci</span></span>
<span class="line"><span>scsi_common            16384  6 scsi_mod,usb_storage,pktcdvd,uas,libata,sr_mod</span></span></code></pre></div><p>Расшифруем что выдаёт команда lsmod:</p><ul><li>первый столбец - имя модуля</li><li>второй столбец - занимаемое им место</li><li>как (в связке с чем) он используется</li></ul><h3 id="команда-modinfo" tabindex="-1">Команда modinfo <a class="header-anchor" href="#команда-modinfo" aria-label="Permalink to &quot;Команда modinfo&quot;">​</a></h3><ul><li>Для того, чтобы посмотреть информацию о модуле ядра используется команда modinfo</li></ul><p>Например:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># modinfo -m acpi-cpufreq.ko</span></span>
<span class="line"><span>или</span></span>
<span class="line"><span># modinfo /lib/modules/$(uname -r)/kernel/drivers/cpufreq/acpi-cpufreq.ko </span></span>
<span class="line"><span></span></span>
<span class="line"><span>filename:       /lib/modules/6.1.10-un-def-alt1/kernel/drivers/cpufreq/acpi-cpufreq.ko</span></span>
<span class="line"><span>alias:          acpi</span></span>
<span class="line"><span>license:        GPL</span></span>
<span class="line"><span>description:    ACPI Processor P-States Driver</span></span>
<span class="line"><span>author:         Paul Diefenbaugh, Dominik Brodowski</span></span>
<span class="line"><span>srcversion:     AEED556A80507DE37550964</span></span>
<span class="line"><span>alias:          cpu:type:x86,ven*fam*mod*:feature:*00E8*</span></span>
<span class="line"><span>alias:          cpu:type:x86,ven*fam*mod*:feature:*0016*</span></span>
<span class="line"><span>alias:          acpi*:ACPI0007:*</span></span>
<span class="line"><span>alias:          acpi*:LNXCPU:*</span></span>
<span class="line"><span>depends:        </span></span>
<span class="line"><span>retpoline:      Y</span></span>
<span class="line"><span>intree:         Y</span></span>
<span class="line"><span>name:           acpi_cpufreq</span></span>
<span class="line"><span>vermagic:       6.1.10-un-def-alt1 SMP preempt mod_unload modversions </span></span>
<span class="line"><span>sig_id:         PKCS#7</span></span>
<span class="line"><span>signer:         Build time autogenerated kernel key</span></span>
<span class="line"><span>sig_key:        1D:99:23:2B:7B:A2:C2:14:28:CF:48:1E:DE:E9:2A:57:D4:83:60:47</span></span>
<span class="line"><span>sig_hashalgo:   sha512</span></span>
<span class="line"><span>signature:      E7:6F:7F:4F:DA:FC:E1:69:42:2B:28:82:BA:B5:44:90:68:32:E5:F6:</span></span>
<span class="line"><span>                7A:03:60:DE:E1:30:DB:8E:37:38:39:4A:3F:12:1E:BC:62:D8:70:A3:</span></span>
<span class="line"><span>                75:CF:4F:2F:9A:BD:09:F3:61:AE:FA:BF:F9:E0:7C:D7:45:21:95:E3:</span></span>
<span class="line"><span> ...</span></span>
<span class="line"><span>                0F:43:AD:84:48:B2:A0:70:52:E0:70:54:BA:6A:5C:0E:41:64:D3:95:</span></span>
<span class="line"><span>                BD:BE:E8:EC:FC:79:C5:40:37:D6:63:0D</span></span>
<span class="line"><span>parm:           acpi_pstate_strict:value 0 or non-zero. non-zero -&gt; strict ACPI checks are performed during frequency changes. (uint)</span></span></code></pre></div><h4 id="как-определить-какие-устроиства-поддерживает-данныи-модуль-ядра-на-примере-nouveau" tabindex="-1">Как определить какие устройства поддерживает данный модуль ядра (на примере nouveau): <a class="header-anchor" href="#как-определить-какие-устроиства-поддерживает-данныи-модуль-ядра-на-примере-nouveau" aria-label="Permalink to &quot;Как определить какие устройства поддерживает данный модуль ядра (на примере nouveau):&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># modinfo -F alias -m nouveau</span></span>
<span class="line"><span>pci:v000012D2d*sv*sd*bc03sc*i*</span></span>
<span class="line"><span>pci:v000010DEd*sv*sd*bc03sc*i*</span></span></code></pre></div><h5 id="расшифровка-алиаса-modinfo" tabindex="-1">Расшифровка алиаса modinfo: <a class="header-anchor" href="#расшифровка-алиаса-modinfo" aria-label="Permalink to &quot;Расшифровка алиаса modinfo:&quot;">​</a></h5><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pci - устройства на шине pci</span></span>
<span class="line"><span>v000012D2 - поддерживаемый вендор</span></span>
<span class="line"><span>d* - поддерживаются все идентификаторы устройства данного вендора (звездочка - означает - все)</span></span></code></pre></div><ul><li>Поддерживаются все ID от Вендоров:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>12d2:* </span></span>
<span class="line"><span>10dE:*</span></span></code></pre></div><h5 id="еще-пример-расшифровки-алиаса" tabindex="-1">Ещё пример расшифровки алиаса: <a class="header-anchor" href="#еще-пример-расшифровки-алиаса" aria-label="Permalink to &quot;Ещё пример расшифровки алиаса:&quot;">​</a></h5><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pci:v00008086d00005A84sv*sd*bc03sc*i*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>8086 - Вендор (intel)</span></span>
<span class="line"><span>5a84 - идентификатор устройства</span></span>
<span class="line"><span>sv*, sd*: Версии поставщика подсистемы и версия подсистемного устройства (все)</span></span>
<span class="line"><span>bc: Базовый класс. Он определяет, что это за устройство - IDE interface, Ethernet controller, USB Controller, ... и т.д.</span></span>
<span class="line"><span>В частности - bc03 - Означает Display controller. </span></span>
<span class="line"><span></span></span>
<span class="line"><span>sc*:  Подкласс к базовому классу (все). </span></span>
<span class="line"><span>i*:   интерфейс                  (все)</span></span></code></pre></div><h4 id="параметры-управления-модулем-ядра" tabindex="-1">Параметры управления модулем ядра <a class="header-anchor" href="#параметры-управления-модулем-ядра" aria-label="Permalink to &quot;Параметры управления модулем ядра&quot;">​</a></h4><p><a href="https://it.wikireading.ru/1966" target="_blank" rel="noreferrer">Параметры модулей ядра</a></p><p>Команда modinfo -F parm выдаёт параметры управлением модулем ядра, например:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># modinfo -F parm -m nouveau</span></span>
<span class="line"><span>vram_pushbuf:Create DMA push buffers in VRAM (int)</span></span>
<span class="line"><span>kms_vram_pushbuf:Place EVO/NVD push buffers in VRAM (default: auto) (int)</span></span>
<span class="line"><span>tv_norm:Default TV norm.</span></span>
<span class="line"><span>                Supported: PAL, PAL-M, PAL-N, PAL-Nc, NTSC-M, NTSC-J,</span></span>
<span class="line"><span>                        hd480i, hd480p, hd576i, hd576p, hd720p, hd1080i.</span></span>
<span class="line"><span>                Default: PAL</span></span>
<span class="line"><span>                *NOTE* Ignored for cards with external TV encoders. (charp)</span></span>
<span class="line"><span>mst:Enable DisplayPort multi-stream (default: enabled) (int)</span></span>
<span class="line"><span>tv_disable:Disable TV-out detection (int)</span></span>
<span class="line"><span>ignorelid:Ignore ACPI lid status (int)</span></span>
<span class="line"><span>duallink:Allow dual-link TMDS (default: enabled) (int)</span></span>
<span class="line"><span>hdmimhz:Force a maximum HDMI pixel clock (in MHz) (int)</span></span>
<span class="line"><span>config:option string to pass to driver core (charp)</span></span>
<span class="line"><span>debug:debug string to pass to driver core (charp)</span></span>
<span class="line"><span>noaccel:disable kernel/abi16 acceleration (int)</span></span>
<span class="line"><span>modeset:enable driver (default: auto, 0 = disabled, 1 = enabled, 2 = headless) (int)</span></span>
<span class="line"><span>atomic:Expose atomic ioctl (default: disabled) (int)</span></span>
<span class="line"><span>runpm:disable (0), force enable (1), optimus only default (-1) (int)</span></span>
<span class="line"><span>NVreg_RegistryDwords:A semicolon-separated list of key=integer pairs of GSP-RM registry keys (charp)</span></span></code></pre></div><p>Перевод на русский:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vram_pushbuf:Создать буферы push DMA в VRAM (целое число)</span></span>
<span class="line"><span>kms_vram_pushbuf:Поместить буферы push EVO/NVD в VRAM (по умолчанию: auto) (целое число)</span></span>
<span class="line"><span>tv_norm: По умолчанию tv_norm</span></span>
<span class="line"><span>                 Поддерживается: PAL, PAL-M, PAL-N, PAL-Nc, NTSC-M, NTSC-J, hd480i, hd480p, hd576i, hd576p, hd720p, hd1080i.</span></span>
<span class="line"><span>По умолчанию: PAL</span></span>
<span class="line"><span>                 *ПРИМЕЧАНИЕ* Игнорируется для карт с внешними ТВ-кодерами (указатель на строку)</span></span>
<span class="line"><span>mst:Разрешить многопоточность DisplayPort (по умолчанию: включено) (целое число)</span></span>
<span class="line"><span>tv_disable: Запретить обнаружение выхода на ТВ (целое число)</span></span>
<span class="line"><span>ignorelid:Игнорировать статус ACPI  (целое число)</span></span>
<span class="line"><span>duallink:Разрешить двухканальный TMDS (по умолчанию: включено) (целое число)</span></span>
<span class="line"><span>hdmimhz:Принудительно установить максимальную тактовую частоту пикселей HDMI (в МГц) (целое число)</span></span>
<span class="line"><span>config:Строка параметров для передачи ядру драйвера (указатель на строку)</span></span>
<span class="line"><span>debug:Строка отладки для передачи ядру драйвера (указатель на строку)</span></span>
<span class="line"><span>noaccel:Отключить ускорение ядра/abi16 (целое число)</span></span>
<span class="line"><span>modeset:Включить драйвер (по умолчанию: авто, 0 = отключено, 1 = включено, 2 = безголовый) (целое число)</span></span>
<span class="line"><span>atomic:Открыть атомарный ioctl (по умолчанию: отключено) (целое число)</span></span>
<span class="line"><span>runpm:Отключить (0), принудительно включить (1), только optimus по умолчанию (-1) (целое)</span></span>
<span class="line"><span>NVreg_RegistryDwords: список пар ключ=целое число ключей реестра GSP-RM, разделенных точкой с запятой (указатель на строку)</span></span></code></pre></div><h3 id="команда-modprobe" tabindex="-1">Команда modprobe <a class="header-anchor" href="#команда-modprobe" aria-label="Permalink to &quot;Команда modprobe&quot;">​</a></h3><ul><li>Для того, чтобы загрузить из командной строки какой либо модуль ядра в ОЗУ можно использовать команду modprobe имя_модуля. Команда modprobe имя_модуля умеет загружать модули из каталога с текущим ядром, и упомянутая в файле /lib/modules/$(uname -r)/modules.dep.</li></ul><p>Пример:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># modprobe xor</span></span>
<span class="line"><span>#</span></span></code></pre></div><p>Если в ответ на команду не было сообщений, то существенных ошибок при загрузке ядра не было (хотя из предыдущего сообщения видно, что модуль уже загружен, надо будет потом проверить всегда-ли так с командой modprobe).</p><ul><li>Проведём маленький эксперимент</li></ul><p>Перед ним модуль nvidia загружен</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># lsmod | grep -e ^nvidia&quot; &quot;</span></span>
<span class="line"><span>nvidia              15884288  1199 nvidia_modeset</span></span></code></pre></div><p>А модуль nouveau нет</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># lsmod | grep -e ^nouveau&quot; &quot;</span></span>
<span class="line"><span>#</span></span></code></pre></div><p>Создадим файл /etc/modprobe.d/my_blacklist.conf с таким содержанием:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>blacklist nouveau</span></span></code></pre></div><p>А теперь по очереди попробуем загрузить эти модули:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># modprobe nvidia</span></span>
<span class="line"><span># </span></span>
<span class="line"><span># modprobe nouveau</span></span>
<span class="line"><span>#</span></span>
<span class="line"><span># modprobe nouveau_bad</span></span>
<span class="line"><span>modprobe: FATAL: Module nouveau_bad not found in directory /lib/modules/6.1.11-un-def-alt1</span></span>
<span class="line"><span>#</span></span>
<span class="line"><span># lsmod | grep -e ^nouveau&quot; &quot;</span></span>
<span class="line"><span>nouveau              2433024  0</span></span>
<span class="line"><span>lsmod | grep -e ^nvidia&quot; &quot;</span></span>
<span class="line"><span>nvidia              15884288  1193 nvidia_modeset</span></span>
<span class="line"><span>#</span></span></code></pre></div><p>Как мы видим</p><ul><li>модуль nouveau не смотря на blacklist загрузился, но не используется (ноль в том месте, где указывается с каким модулем связан) [^12]</li><li>не было никаких сообщений о том, что модуль nvidia уже загружен</li><li>было сообщение, что модуля nouveau_bad не существует [^13]</li></ul><p>Что-бы не ломать работу систему в будушем, я удаляю файл /etc/modprobe.d/my_blacklist.conf, если кто повторял мой эксперимент, советую сделать это и вам;-)</p><h3 id="команда-insmod" tabindex="-1">Команда insmod <a class="header-anchor" href="#команда-insmod" aria-label="Permalink to &quot;Команда insmod&quot;">​</a></h3><ul><li>Второй способ загрузки модуля ядра, это выполнение команды insmod, она позволяет загружать модуль из заданного каталога, например:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># insmod /lib/modules/$(uname -r)/kernel/drivers/cpufreq/acpi-cpufreq.ko </span></span>
<span class="line"><span># insmod /lib/modules/$(uname -r)/kernel/drivers/cpufreq/acpi-cpufreq.ko </span></span>
<span class="line"><span>insmod: ERROR: could not insert module /lib/modules/6.1.10-un-def-alt1/kernel/drivers/cpufreq/acpi-cpufreq.ko: File exists</span></span></code></pre></div><p>Здесь я преднамеренно попытался загрузить командой insmod один и тот-же модуль. В первый раз всё прошло без ошибок, а второй раз выдало информацию об ошибке (модуль уже загружен).</p><h3 id="команда-rmmod" tabindex="-1">Команда rmmod <a class="header-anchor" href="#команда-rmmod" aria-label="Permalink to &quot;Команда rmmod&quot;">​</a></h3><ul><li>Для того, чтобы выгрузить модуль ядра rmmod имя_модуля.</li></ul><p>Важно заметить, что работающий с устройством модуль нельзя выгрузить.</p><p>Пример 1:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># rmmod  acpi-cpufreq</span></span>
<span class="line"><span>#</span></span></code></pre></div><p>Модуль был выгружен из ОЗУ без ошибок, что в принципе означает, что модуль в данный момент был не задействован.</p><p>Пример 2:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># rmmod nvidia</span></span>
<span class="line"><span>rmmod: ERROR: Module nvidia is in use by: nvidia_modeset</span></span></code></pre></div><p>Попытка выгрузки модуля не удалась, так-как он задействован в работе с железом.</p><h3 id="_14" tabindex="-1">14 <a class="header-anchor" href="#_14" aria-label="Permalink to &quot;14&quot;">​</a></h3><ul><li>Для того, чтобы посмотреть события, произошедшие с ядром, можно использовать команду dmesg</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># dmesg | tail -n2</span></span>
<span class="line"><span>[28945.743841] nvidia_modeset: disagrees about version of symbol module_layout</span></span>
<span class="line"><span>[29157.059850] acpi_cpufreq: overriding BIOS provided _PSD data</span></span></code></pre></div><p>Мы видим последние два сообщения ядра.</p><p>Реальный пример использования dmesg с <a href="https://forum.altlinux.org/index.php?topic=39188.msg313469#msg313469" target="_blank" rel="noreferrer">форума ALT Linux</a></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># dmesg | grep -A6 -B2 firmware</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[    0.000000]   HighMem zone: 296802 pages, LIFO batch:31</span></span>
<span class="line"><span>[    0.000000] Using APIC driver default</span></span>
<span class="line"><span>[    0.000000] SFI: Simple Firmware Interface v0.81 http://simplefirmware.org</span></span>
<span class="line"><span>[    0.000000] Local APIC disabled by BIOS -- you can enable it with &quot;lapic&quot;</span></span>
<span class="line"><span>[    0.000000] APIC: disable apic facility</span></span>
<span class="line"><span>[    0.000000] APIC: switched to apic NOOP</span></span>
<span class="line"><span>[    0.000000] smpboot: Allowing 1 CPUs, 0 hotplug CPUs</span></span>
<span class="line"><span>[    0.000000] PM: Registered nosave memory: [mem 0x00000000-0x00000fff]</span></span>
<span class="line"><span>[    0.000000] PM: Registered nosave memory: [mem 0x0009f000-0x0009ffff]</span></span></code></pre></div><h3 id="команда-udevadm" tabindex="-1">Команда udevadm <a class="header-anchor" href="#команда-udevadm" aria-label="Permalink to &quot;Команда udevadm&quot;">​</a></h3><ul><li>Для анализа событий происходящих в момент подсоединения, или отсоединения устройства пригодятся команды мониторинга udevadm</li></ul><p>Пример:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># udevadm monitor</span></span>
<span class="line"><span>monitor will print the received events for:</span></span>
<span class="line"><span>UDEV - the event which udev sends out after rule processing</span></span>
<span class="line"><span>KERNEL - the kernel uevent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>KERNEL[30557.800595] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2 (usb)</span></span>
<span class="line"><span>KERNEL[30557.802173] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0 (usb)</span></span>
<span class="line"><span>KERNEL[30557.806378] add      /devices/virtual/workqueue/scsi_tmf_9 (workqueue)</span></span>
<span class="line"><span>KERNEL[30557.806434] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0/host9 (scsi)</span></span>
<span class="line"><span>KERNEL[30557.806470] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0/host9/scsi_host/host9 (scsi_host)</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>UDEV  [30558.029462] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0/host9/target9:0:0/9:0:0:0/block/sdi (block)</span></span>
<span class="line"><span>UDEV  [30558.092521] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0/host9/target9:0:0/9:0:0:0/block/sdi/sdi2 (block)</span></span>
<span class="line"><span>UDEV  [30558.133565] add      /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0/host9/target9:0:0/9:0:0:0/block/sdi/sdi1 (block)</span></span>
<span class="line"><span>UDEV  [30558.135974] bind     /devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0/host9/target9:0:0/9:0:0:0 (scsi)</span></span></code></pre></div><p>Вот так показывает udevadm события, связанные с вставлением внешнего диска.</p><ul><li>Здесь сообщения, начинающиеся со слова KERNEL - это сообщения ядра, сообщения начинающиеся со слова UDEV - сообщения UDEV.</li><li>[30558.133565] - это время события</li><li>add - это выполняемая операция</li><li>/devices/pci0000:00/0000:00:10.0/usb5/5-2/5-2:1.0 (usb) - это адрес устройства внутри файловой системы /sys</li></ul><h2 id="немного-о-драиверах-видеокарт" tabindex="-1">Немного о драйверах видеокарт <a class="header-anchor" href="#немного-о-драиверах-видеокарт" aria-label="Permalink to &quot;Немного о драйверах видеокарт&quot;">​</a></h2><p>Для работы видео карт в графическом режиме помимо драйвера ядра, требуются модули графического сервера (например xorg).</p><p>Так для работы карт <a href="https://www.altlinux.org/Nvidia" title="Nvidia" target="_blank" rel="noreferrer">nvidia</a> требуется модуль ядра и соответствующий ему модуль xorg.</p><p>Для проприетарного модуля ядра nvidia, входящего в пакет kernel-modules-nvidia, требуется графический модуль xorg, входящий в пакет nvidia_glx_версия_модуля.</p><p>А для свободного драйвера nouveau (пакет kernel-modules-drm-nouvea..), также умеющего работать с картами nvidia требуется графический модуль nouveau (пакеты xorg-drv-nouveau и xorg-dri-nouveau).</p><p>Это касается не только карт Nvidia, но и многих других видеокарт. В последнее время появилась тенденция большую часть поддержки стандартных и наиболее часто встречающихся карт переносить внутрь ядра, оставляя только несколько универсальных графических модулей xorg (см <a href="https://wiki.archlinux.org/title/Kernel_mode_setting_(%D0%A0%D1%83%D1%81%D1%81%D0%BA%D0%B8%D0%B9)" target="_blank" rel="noreferrer">Kernel mode setting</a>).</p><h2 id="примечания" tabindex="-1">Примечания <a class="header-anchor" href="#примечания" aria-label="Permalink to &quot;Примечания&quot;">​</a></h2><h2 id="ссылки" tabindex="-1">Ссылки <a class="header-anchor" href="#ссылки" aria-label="Permalink to &quot;Ссылки&quot;">​</a></h2><p><a href="https://www.altlinux.org/%D0%9F%D1%80%D0%BE%D0%B1%D0%B0_%D0%BE%D0%B1%D0%BE%D1%80%D1%83%D0%B4%D0%BE%D0%B2%D0%B0%D0%BD%D0%B8%D1%8F" title="Проба оборудования" target="_blank" rel="noreferrer">Проба_оборудования</a></p><p>[^1]: строго говоря LPT и Com-порты не шины, например COM-порты это выход шины RS32</p><p>[^2]: lsusb — утилита для вывода информации о шинах USB в системе и подключенных к ним устройствах.</p><p>[^3]: Существуют и другие способы выяснения с каким модулем ядра работает данное устройство часть из них описана, например <a href="https://unix.stackexchange.com/questions/60078/find-out-which-modules-are-associated-with-a-usb-device" target="_blank" rel="noreferrer">здесь</a></p><p>[^4]: Утилита lspci служит для вывода информации о всех имеющихся в системе шинах PCI и всех подключенных к ним устройствах.</p><p>[^5]: в жаргоне их часто просто называют &quot;дровами&quot;</p><p>[^6]: Конечно это ОС, но и благодаря лицензии GPL, это очень удобная среда в которой программисты могут делиться своими знаниями и наработками. Впрочем это вопрос отдельной статьи</p><p>[^7]: Обязательная часть здесь только расширение conf, имя файла выбирается с учетом того, что-бы было легче что находится внутри</p><p>[^8]: Имя релиза загруженного ядра выдаёт команда uname -r</p><p>[^9]: Проект по анонимному сбору сведений об оборудовании компьютеров под управлением Linux по всему миру и помощи людям в совместном устранении проблем, связанных с оборудованием, проверке совместимости с Linux и поиске драйверов. Смотри так-же <a href="https://www.altlinux.org/%D0%9F%D1%80%D0%BE%D0%B1%D0%B0_%D0%BE%D0%B1%D0%BE%D1%80%D1%83%D0%B4%D0%BE%D0%B2%D0%B0%D0%BD%D0%B8%D1%8F" title="Проба оборудования" target="_blank" rel="noreferrer">о пробах оборудования</a></p><p>[^10]: Для анализа таких ситуаций помогает анализ выдачи команды dmesg.</p><p>[^11]: К сожалению на момент написания статьи он не представлен в текущем ядре</p><p>[^12]: Я сам удивился, когда увидел, что он загрузился;-). Если я где-то ошибся дайте знать;-) Меня самого смущает этот результат</p><p>[^13]: Естественно, ведь я его только сейчас выдумал</p><p>[^14]: В системах с systemd можно так-же использовать команду journalctl -bk (см <a href="https://www.altlinux.org/Journald" title="Journald" target="_blank" rel="noreferrer">Журналирование в systemd</a>)</p>`,161)]))}const b=a(i,[["render",l]]);export{h as __pageData,b as default};
